use std::sync::atomic::{AtomicU64, Ordering};
use std::sync::Arc;

use axum::body::Body;
use axum::http::{Request, StatusCode};
use axum::middleware::Next;
use axum::response::Response;

#[derive(Clone)]
pub struct RateLimitState {
    window_epoch: Arc<AtomicU64>,
    count: Arc<AtomicU64>,
    max_per_window: u64,
}

impl RateLimitState {
    pub fn new(max_per_window: u64) -> Self {
        Self {
            window_epoch: Arc::new(AtomicU64::new(0)),
            count: Arc::new(AtomicU64::new(0)),
            max_per_window,
        }
    }
}

pub async fn middleware(
    axum::Extension(state): axum::Extension<RateLimitState>,
    req: Request<Body>,
    next: Next,
) -> Result<Response, StatusCode> {
    let now = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .unwrap_or_default()
        .as_secs();
    let epoch = state.window_epoch.load(Ordering::Relaxed);
    if now.saturating_sub(epoch) >= 60 {
        state.window_epoch.store(now, Ordering::Relaxed);
        state.count.store(0, Ordering::Relaxed);
    }
    let n = state.count.fetch_add(1, Ordering::Relaxed);
    if n >= state.max_per_window {
        return Err(StatusCode::TOO_MANY_REQUESTS);
    }
    Ok(next.run(req).await)
}
